function normalizeLineEndings(e){return e.replace(/\r\n/g,"\n").replace(/\r/g,"\n")}function openCode(e){const t=document.getElementById("codeModal"),o=document.getElementById("modalTitle"),n=document.getElementById("codeBlock"),a=n?.closest("pre");if(!t||!o||!n)return;o.textContent=e,n.textContent="Carregando código...";const r=e.endsWith(".jsx")?"language-jsx":"language-python";n.className=r,a&&(a.className=r),fetch(e).then(e=>{if(!e.ok)throw new Error("Arquivo não encontrado");return e.text()}).then(e=>{const t=normalizeLineEndings(e);n.textContent=t,"undefined"!=typeof Prism&&Prism.highlightElement(n)}).catch(e=>{n.textContent=`ERRO: ${e.message}\n\nArquivo ausente no repositório.`}),t.classList.add("show"),t.setAttribute("aria-hidden","false")}function closeCode(){const e=document.getElementById("codeModal");e&&(e.classList.remove("show"),e.setAttribute("aria-hidden","true"))}document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("codeModal");e&&(e.addEventListener("click",e=>{e.target===e.currentTarget&&closeCode()}),document.addEventListener("keydown",e=>{"Escape"===e.key&&closeCode()}))});
